import{_ as r,o as a,c as e,a2 as n}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"📊 市場情緒日報 — 2026年6月3日（週三）","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/市場情緒/市場情緒_20260603.md","filePath":"Deep32Q知識庫/市場情緒/市場情緒_20260603.md"}'),o={name:"Deep32Q知識庫/市場情緒/市場情緒_20260603.md"};function i(l,t,s,d,g,h){return a(),e("div",null,[...t[0]||(t[0]=[n('<h1 id="📊-市場情緒日報-—-2026年6月3日-週三" tabindex="-1">📊 市場情緒日報 — 2026年6月3日（週三） <a class="header-anchor" href="#📊-市場情緒日報-—-2026年6月3日-週三" aria-label="Permalink to &quot;📊 市場情緒日報 — 2026年6月3日（週三）&quot;">​</a></h1><blockquote><p><strong>查詢時間</strong>：TST 05:30 (2026-06-02 21:30 UTC) <strong>敘事錨點</strong>：🔥 伊朗暫停和談 + 荷莫茲封鎖 94 天 + 油價回落但仍在 $90+ → 美股期貨微跌；台股 45,557 歷史新高 + COMPUTEX 本週 + 台積電 +1.06%</p></blockquote><hr><h2 id="🔑-今日最大事件-前3點深度敘事" tabindex="-1">🔑 今日最大事件（前3點深度敘事） <a class="header-anchor" href="#🔑-今日最大事件-前3點深度敘事" aria-label="Permalink to &quot;🔑 今日最大事件（前3點深度敘事）&quot;">​</a></h2><h3 id="_1-🇺🇸🇮🇷-伊朗暫停和談-荷莫茲封鎖-94-天-—-trump-仍稱「本週可達協議」" tabindex="-1">1. 🇺🇸🇮🇷 伊朗暫停和談，荷莫茲封鎖 94 天 — Trump 仍稱「本週可達協議」 <a class="header-anchor" href="#_1-🇺🇸🇮🇷-伊朗暫停和談-荷莫茲封鎖-94-天-—-trump-仍稱「本週可達協議」" aria-label="Permalink to &quot;1. 🇺🇸🇮🇷 伊朗暫停和談，荷莫茲封鎖 94 天 — Trump 仍稱「本週可達協議」&quot;">​</a></h3><ul><li><strong>最新動態（6/1-2）</strong>： <ul><li>伊朗 6/1 宣布<strong>暫停與美國和談</strong>，作為對以色列在黎巴嫩軍事行動的回應</li><li>Trump 6/2 稱談判仍在進行，預期荷莫茲海峽重新開放協議「<strong>可能在本週達成</strong>」</li><li>荷莫茲海峽仍實質關閉，約 <strong>1,400 萬桶/日</strong> 石油運輸受阻（占全球 14%）</li><li>伊朗 5 月底部署額外海雷，持續限制油輪通行</li><li>市場分析：若停火協議破裂，油價可能觸及 <strong>$150/桶</strong></li><li>即便達成協議，Fullerton 海峽全面復航需數月（掃雷 + 路線安全），Brent 可能維持 $90 至 Q4</li></ul></li><li><strong>影響鏈</strong>：伊朗暫停和談 → 升級風險增加 → 油價支撐 → 通膨壓力 → Fed 升息預期 → 金價支撐 vs 美元走強</li><li>來源：<a href="https://www.theguardian.com/us-news/2026/jun/02/marco-rubio-iran-war-congress-hearing" target="_blank" rel="noreferrer">The Guardian</a>、<a href="https://www.cbsnews.com/live-updates/iran-war-us-trump-strikes-ceasefire-lebanon-israel/" target="_blank" rel="noreferrer">CBS News</a>、<a href="https://www.armscontrol.org/act/2026-06/news/trump-says-us-iran-close-deal" target="_blank" rel="noreferrer">ArmsControl</a>（TST 05:30）</li></ul><h3 id="_2-💻-computex-2026-本週-台股-45-557-歷史新高-台積電-1-06" tabindex="-1">2. 💻 COMPUTEX 2026 本週 + 台股 45,557 歷史新高 + 台積電 +1.06% <a class="header-anchor" href="#_2-💻-computex-2026-本週-台股-45-557-歷史新高-台積電-1-06" aria-label="Permalink to &quot;2. 💻 COMPUTEX 2026 本週 + 台股 45,557 歷史新高 + 台積電 +1.06%&quot;">​</a></h3><ul><li><strong>台股 6/2 收盤</strong>：TAIEX <strong>45,557.34</strong>（+219.40，+0.48%），<strong>歷史新高</strong></li><li><strong>台指期</strong>：46,087（+46），正價差 529.69 點</li><li><strong>台積電（2330）</strong>：6/2 +1.06%，貢獻 TAIEX 約 200 點</li><li><strong>COMPUTEX 2026</strong>：6/2-5 台北南港展覽館，主題「AI Together」</li><li><strong>黃仁勳 GTC Taipei</strong>：6/1 發表 RTX Spark + Vera Rubin + $40 億光子投資</li><li><strong>台灣市值</strong>：已躍升全球第五大，81.44% 集中科技產業</li><li><strong>Lai 總統</strong>：台灣 2027 年有望晉升全球前 20 大經濟體</li><li>來源：<a href="https://www.taiwannews.com.tw/news/6374782" target="_blank" rel="noreferrer">Taiwan News</a>、<a href="https://news.cnyes.com/news/id/6469850" target="_blank" rel="noreferrer">鉅亨網</a>、<a href="https://tradingeconomics.com/taiwan/stock-market" target="_blank" rel="noreferrer">TradingEconomics</a>（TST 05:30）</li></ul><h3 id="_3-🇺🇸-美股期貨微跌-s-p-500-0-18-nasdaq-0-1-0-3-ai-驅動牛市延續" tabindex="-1">3. 🇺🇸 美股期貨微跌：S&amp;P 500 -0.18%，Nasdaq -0.1%~0.3%，AI 驅動牛市延續 <a class="header-anchor" href="#_3-🇺🇸-美股期貨微跌-s-p-500-0-18-nasdaq-0-1-0-3-ai-驅動牛市延續" aria-label="Permalink to &quot;3. 🇺🇸 美股期貨微跌：S&amp;P 500 -0.18%，Nasdaq -0.1%~0.3%，AI 驅動牛市延續&quot;">​</a></h3><ul><li><strong>6/2 盤後/6/3 盤前期貨</strong>： <ul><li>S&amp;P 500 期貨：<strong>-0.18%</strong></li><li>Nasdaq 100 期貨：<strong>-0.1%~-0.30%</strong></li></ul></li><li><strong>6/1 收盤</strong>：S&amp;P 500 穩定在高位，Nasdaq + 費半漲幅較大</li><li><strong>亮點</strong>：AMD、Nvidia、台積電 ADR 6/1 漲跌互見</li><li><strong>背景</strong>：S&amp;P 500 連漲 9 週創紀錄（5/29 收），分析師目標 7,700-8,000</li><li><strong>CEO 信心下降</strong>：Q2 2026 CEO 信心指數下滑，多數預期未來 6 個月經濟惡化</li><li>來源：<a href="https://www.barchart.com/futures/quotes/NQM26" target="_blank" rel="noreferrer">Barchart</a>、<a href="https://www.tradingkey.com/analysis/stocks/us-stocks/261941423-us-stock-market-pre-hpe-surged-27-ai-boom-middle-east-risks-tradingkey" target="_blank" rel="noreferrer">TradingKey</a>（TST 05:30）</li></ul><hr><h2 id="📋-次要事件-第4-8點" tabindex="-1">📋 次要事件（第4-8點） <a class="header-anchor" href="#📋-次要事件-第4-8點" aria-label="Permalink to &quot;📋 次要事件（第4-8點）&quot;">​</a></h2><h3 id="_4-⛽-油價回落但仍在高檔-wti-90-7-1-58-brent-94-34-96" tabindex="-1">4. ⛽ 油價回落但仍在高檔：WTI $90.7（-1.58%），Brent $94.34-$96 <a class="header-anchor" href="#_4-⛽-油價回落但仍在高檔-wti-90-7-1-58-brent-94-34-96" aria-label="Permalink to &quot;4. ⛽ 油價回落但仍在高檔：WTI $90.7（-1.58%），Brent $94.34-$96&quot;">​</a></h3><ul><li><strong>WTI（7 月）</strong>：$90.7/bbl（-1.58%），日內曾觸 $94.81 後回落</li><li><strong>Brent（8 月）</strong>：$93.38-$96.01 區間，-$1.68~-$0.15</li><li><strong>驅動回落</strong>：Hezbollah 停火傳聞 + 美伊和談重啟希望</li><li><strong>但底部支撐</strong>：荷莫茲實質關閉 → 1,400 萬桶/日缺失 → 油價難跌破 $85</li><li><strong>通膨傳導</strong>：CPI 3.8%，能源 +17.9% YoY → Fed 升息預期</li><li>來源：<a href="https://www.ttnews.com/articles/oil-prices-dip-still-no-agreement-reopen-hormuz" target="_blank" rel="noreferrer">TTNews</a>、<a href="https://www.thenationalnews.com/business/energy/2026/06/02/oil-prices-slide-on-hezbollah-ceasefire-and-iran-peace-talks/" target="_blank" rel="noreferrer">TheNational</a>、<a href="https://tradingeconomics.com/commodity/brent-crude-oil" target="_blank" rel="noreferrer">TradingEconomics</a>（TST 05:30）</li></ul><h3 id="_5-🥇-黃金-4-488-微漲-0-07-油價回落緩解通膨-vs-美元走強拉鋸" tabindex="-1">5. 🥇 黃金 $4,488 微漲 0.07%：油價回落緩解通膨 vs 美元走強拉鋸 <a class="header-anchor" href="#_5-🥇-黃金-4-488-微漲-0-07-油價回落緩解通膨-vs-美元走強拉鋸" aria-label="Permalink to &quot;5. 🥇 黃金 $4,488 微漲 0.07%：油價回落緩解通膨 vs 美元走強拉鋸&quot;">​</a></h3><ul><li><strong>XAU/USD</strong>：$4,488.19（+0.07%），前收 $4,485</li><li><strong>日內區間</strong>：$4,458-$4,544</li><li><strong>交叉驗證</strong>：LiteFinance $4,488.27 vs TradingEconomics $4,488.19 → 一致性高 ✅</li><li><strong>驅動</strong>： <ul><li>利多：油價回落 → 通膨擔憂緩解 → 遷延避險需求 → 金價反彈</li><li>利空：美元走強（DXY 99.22）+ Fed 升息預期 → 上行受限</li></ul></li><li><strong>歷史高</strong>：$5,608.35（2026 年 1 月）</li><li>來源：<a href="https://tradingeconomics.com/commodity/gold" target="_blank" rel="noreferrer">TradingEconomics</a>、<a href="https://www.litefinance.org/blog/analysts-opinions/gold-price-prediction-forecast/daily-and-weekly/" target="_blank" rel="noreferrer">LiteFinance</a>（TST 05:30）</li></ul><h3 id="_6-💵-美元指數-99-22-穩定-dxy-微升-fed-升息預期支撐" tabindex="-1">6. 💵 美元指數 99.22 穩定：DXY 微升，Fed 升息預期支撐 <a class="header-anchor" href="#_6-💵-美元指數-99-22-穩定-dxy-微升-fed-升息預期支撐" aria-label="Permalink to &quot;6. 💵 美元指數 99.22 穩定：DXY 微升，Fed 升息預期支撐&quot;">​</a></h3><ul><li><strong>DXY</strong>：99.2168（6/2 收），開盤 99.18，日高 99.23，日低 99.05</li><li><strong>驅動</strong>：Fed 升息預期（市場已排除 2026 降息，計入升息可能）</li><li><strong>連鎖反應</strong>：美元穩 → 金價承壓 → 亞幣承壓（KRW 157、JPY 159 區間）</li><li>來源：<a href="https://tradingeconomics.com/united-states/currency" target="_blank" rel="noreferrer">TradingEconomics</a>、<a href="https://www.tradingview.com/news/te_news:555781:0-dollar-little-changed-on-tuesday/" target="_blank" rel="noreferrer">TradingView</a>（TST 05:30）</li></ul><h3 id="_7-🫘-黃豆跌至-11-645-1-38-兩周低點-供給壓力-中國需求疲軟" tabindex="-1">7. 🫘 黃豆跌至 $11.645（-1.38%）：兩周低點，供給壓力 + 中國需求疲軟 <a class="header-anchor" href="#_7-🫘-黃豆跌至-11-645-1-38-兩周低點-供給壓力-中國需求疲軟" aria-label="Permalink to &quot;7. 🫘 黃豆跌至 $11.645（-1.38%）：兩周低點，供給壓力 + 中國需求疲軟&quot;">​</a></h3><ul><li><strong>CBOT 7 月黃豆</strong>：$11.6450/bu（-1.38%），前收 $11.8075</li><li><strong>USDA 種植進度</strong>：87%（五年平均 80%），出芽 65%（五年平均 57%）</li><li><strong>品質</strong>：Good-to-Excellent 66%，略低於市場預期 67-68%</li><li><strong>巴西出口</strong>：截至 5 月已出口 5,160 萬噸，超越 2025 同期</li><li>來源：<a href="https://tradingeconomics.com/commodity/soybeans" target="_blank" rel="noreferrer">TradingEconomics</a>、<a href="https://www.morningstar.com/news/dow-jones/202606026699/soybean-futures-decline-as-rainfall-buoys-crop-conditions-daily-grain-highlights" target="_blank" rel="noreferrer">Morningstar</a>（TST 05:30）</li></ul><h3 id="_8-🇮🇱🇱🇧-以色列-真主黨升級-beaufort-城堡陷落-法國要求安理會緊急會議" tabindex="-1">8. 🇮🇱🇱🇧 以色列-真主黨升級：Beaufort 城堡陷落 + 法國要求安理會緊急會議 <a class="header-anchor" href="#_8-🇮🇱🇱🇧-以色列-真主黨升級-beaufort-城堡陷落-法國要求安理會緊急會議" aria-label="Permalink to &quot;8. 🇮🇱🇱🇧 以色列-真主黨升級：Beaufort 城堡陷落 + 法國要求安理會緊急會議&quot;">​</a></h3><ul><li>以軍佔領黎巴嫩 Beaufort 城堡（25 年來最深入黎巴嫩軍事行動）</li><li>Netanyahu 稱此為「戲劇性轉折」</li><li>法國要求 UN 安理會緊急會議</li><li>伊朗以此為由暫停和談 → 升級螺旋風險</li><li>來源：<a href="https://www.hindustantimes.com/world-news/us-iran-war-news-live-updates-ceasefire-peace-deal-donald-trump-strikes-strait-of-hormuz-netanyahu-israel-lebanon-latest-101780187912874.html" target="_blank" rel="noreferrer">Hindustan Times</a>、<a href="https://understandingwar.org/research/middle-east/iran-update-special-report-june-1-2026/" target="_blank" rel="noreferrer">UnderstandingWar</a>（TST 05:30）</li></ul><hr><h2 id="🔮-前瞻預警-第9-10點" tabindex="-1">🔮 前瞻預警（第9-10點） <a class="header-anchor" href="#🔮-前瞻預警-第9-10點" aria-label="Permalink to &quot;🔮 前瞻預警（第9-10點）&quot;">​</a></h2><h3 id="_9-📅-本週焦點-非農就業-6-6-broadcom-盤後財報-6-3-wasde-6-12" tabindex="-1">9. 📅 本週焦點：非農就業 6/6 + Broadcom 盤後財報 6/3 + WASDE 6/12 <a class="header-anchor" href="#_9-📅-本週焦點-非農就業-6-6-broadcom-盤後財報-6-3-wasde-6-12" aria-label="Permalink to &quot;9. 📅 本週焦點：非農就業 6/6 + Broadcom 盤後財報 6/3 + WASDE 6/12&quot;">​</a></h3><ul><li><strong>6/3 盤後</strong>：Broadcom Q2 FY2026 財報（AI 收入預估 $107 億）</li><li><strong>6/6（週五）</strong>：美國非農就業報告（NFP）— Fed 政策關鍵參考</li><li><strong>6/10</strong>：美國 5 月 CPI</li><li><strong>6/12</strong>：USDA WASDE 報告（黃豆 2026/27 年度更新）</li><li>來源：<a href="https://seekingalpha.com/news/4599887-broadcom-q2-2026-earnings-preview" target="_blank" rel="noreferrer">SeekingAlpha</a>（TST 05:30）</li></ul><h3 id="_10-🌍-地緣風險全景-美伊僵局-以色列升級-荷莫茲封鎖-94-天" tabindex="-1">10. 🌍 地緣風險全景：美伊僵局 + 以色列升級 + 荷莫茲封鎖 94 天 <a class="header-anchor" href="#_10-🌍-地緣風險全景-美伊僵局-以色列升級-荷莫茲封鎖-94-天" aria-label="Permalink to &quot;10. 🌍 地緣風險全景：美伊僵局 + 以色列升級 + 荷莫茲封鎖 94 天&quot;">​</a></h3><ul><li><strong>美伊</strong>：伊朗暫停和談 → Trump 稱本週可達協議 → 不確定性極高</li><li><strong>荷莫茲</strong>：封鎖 94 天，1,400 萬桶/日缺失，57 艘 VLCC 滯留</li><li><strong>以色列-真主黨</strong>：Beaufort 陷落 → 法國介入 → 衝突升級</li><li><strong>風險平衡</strong>：AI 驅動牛市（COMPUTEX + 台股新高）vs 地緣不確定性 vs 通膨/利率 → 高波動環境</li></ul><hr><h2 id="📚-資料來源" tabindex="-1">📚 資料來源 <a class="header-anchor" href="#📚-資料來源" aria-label="Permalink to &quot;📚 資料來源&quot;">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>來源</th><th>日期</th><th>內容</th></tr></thead><tbody><tr><td>1</td><td>The Guardian</td><td>2026-06-02</td><td>Rubio 國會聽證，伊朗和談</td></tr><tr><td>2</td><td>CBS News</td><td>2026-06-02</td><td>伊朗暫停和談</td></tr><tr><td>3</td><td>ArmsControl</td><td>2026-06-02</td><td>Trump 稱本週可達協議</td></tr><tr><td>4</td><td>Taiwan News</td><td>2026-06-02</td><td>台股首度收上 45,000</td></tr><tr><td>5</td><td>鉅亨網</td><td>2026-06-02</td><td>台積電 + COMPUTEX</td></tr><tr><td>6</td><td>Barchart</td><td>2026-06-02</td><td>S&amp;P 500 / Nasdaq 期貨</td></tr><tr><td>7</td><td>TTNews</td><td>2026-06-02</td><td>油價回落，荷莫茲未解</td></tr><tr><td>8</td><td>TheNational</td><td>2026-06-02</td><td>Brent 跌破 $95</td></tr><tr><td>9</td><td>TradingEconomics</td><td>2026-06-02</td><td>黃金 $4,488、黃豆 $11.645、DXY 99.22</td></tr><tr><td>10</td><td>LiteFinance</td><td>2026-06-02</td><td>XAU/USD 交叉驗證</td></tr><tr><td>11</td><td>Morningstar</td><td>2026-06-02</td><td>黃豆下跌，降雨有利</td></tr><tr><td>12</td><td>SeekingAlpha</td><td>2026-06-02</td><td>Broadcom 盤後財報預覽</td></tr></tbody></table><hr><p><em>報告生成時間：2026-06-03 05:30 TST</em></p>',33)])])}const m=r(o,[["render",i]]);export{u as __pageData,m as default};
